```tsx
import { createMachine, assign, fromPromise, createActor } from 'xstate';

// Define event types
type Event =
  | { type: 'NEXT' }
  | { type: 'PREV' }
  | { type: 'SET_EMAIL'; payload: { email: string } }
  | { type: 'SET_PASSWORD'; payload: { password: string } }
  | { type: 'SET_CONFIRM_PASSWORD'; payload: { confirmPassword: string } };

// Define context interface
interface Context {
  step: 'email' | 'password' | 'confirm';
  email?: string;
  password?: string;
  confirmPassword?: string;
  emailValid?: boolean;
}

// Email validation service
const validateEmailService = fromPromise((email: string) => {
  return fetch(`https://api.example.com/validate-email?email=${encodeURIComponent(email)}`)
    .then((response) => response.json())
    .then((data) => {
      if (data.unique) {
        return { unique: true };
      } else {
        throw new Error('Email already taken');
      }
    });
});

// Create the machine
const signupMachine = createMachine<Context, Event>(
  {
    id: 'signup',
    initial: 'email',
    context: {
      step: 'email',
      email: '',
      password: '',
      confirmPassword: '',
      emailValid: undefined,
    },
    states: {
      email: {
        on: {
          NEXT: [
            {
              target: 'email',
              cond: (context) => !context.email,
              actions: assign({ emailValid: false }),
            },
            {
              target: 'email',
              cond: (context) => context.email && context.emailValid === false,
              actions: assign({ emailValid: undefined }),
            },
            {
              target: 'password',
              cond: (context) => context.emailValid === true,
              actions: assign({ step: 'password' }),
            },
            {
              target: 'email',
              cond: (context) => context.email && context.emailValid === undefined,
              actions: [
                assign({ emailValid: undefined }),
                invoke({
                  id: 'validateEmail',
                  src: 'validateEmailService',
                  input: (context) => context.email,
                  onDone: {
                    target: 'password',
                    actions: assign({ emailValid: true }),
                  },
                  onError: {
                    target: 'email',
                    actions: assign({ emailValid: false }),
                  },
                }),
              ],
            },
          ],
          SET_EMAIL: {
            actions: assign((context, event) => ({
              ...context,
              email: event.payload.email,
            })),
          },
          PREV: {
            target: 'email',
          },
        },
      },
      password: {
        on: {
          NEXT: [
            {
              target: 'confirm',
              cond: (context) => context.password,
              actions: assign({ step: 'confirm' }),
            },
            {
              target: 'password',
              cond: (context) => !context.password,
              actions: assign({ emailValid: false }),
            },
          ],
          SET_PASSWORD: {
            actions: assign((context, event) => ({
              ...context,
              password: event.payload.password,
            })),
          },
          PREV: {
            target: 'email',
          },
        },
      },
      confirm: {
        on: {
          NEXT: [
            {
              target: 'done',
              cond: (context) => context.password === context.confirmPassword,
              actions: assign({ step: 'done' }),
            },
            {
              target: 'confirm',
              cond: (context) => context.password !== context.confirmPassword,
              actions: assign({ emailValid: false }),
            },
          ],
          SET_CONFIRM_PASSWORD: {
            actions: assign((context, event) => ({
              ...context,
              confirmPassword: event.payload.confirmPassword,
            })),
          },
          PREV: {
            target: 'password',
          },
        },
      },
      done: {
        type: 'final',
      },
    },
  },
  {
    services: {
      validateEmailService,
    },
  }
);

export default signupMachine;
```

---

### ✅ Summary

- **Typed Events**: Events like `NEXT`, `PREV`, and field-setting events (`SET_EMAIL`, etc.) are explicitly typed.
- **Multi-step Form**: The machine transitions through `email`, `password`, and `confirm` states.
- **Email Validation**: Uses `fromPromise` to call an API endpoint for email uniqueness, with proper success/failure handling.
- **Context Management**: The context keeps track of the current step, field values, and validation status.
