### 🧩 Implementation

Here is the complete implementation using RxJS:

```ts
import { combineLatest, Observable } from 'rxjs';
import { map } from 'rxjs/operators';

// Assume these are defined elsewhere and are of type Observable<User>, Observable<Settings>, Observable<Theme>
const user$: Observable<User> = ...;
const settings$: Observable<Settings> = ...;
const theme$: Observable<Theme> = ...;

interface ViewModel {
  user: User;
  settings: Settings;
  theme: Theme;
}

// Combine the three Observables and map the result to a ViewModel
const viewModel$: Observable<ViewModel> = combineLatest([user$, settings$, theme$]).pipe(
  map(([user, settings, theme]) => ({
    user,
    settings,
    theme,
  }))
);
```

