### ✅ Example: Processing File Uploads with Concurrency Control

```typescript
import { from } from 'rxjs';
import { mergeMap } from 'rxjs/operators';

// Simulated upload function that returns an Observable<Progress>
function uploadFile(file: File): Observable<Progress> {
  return new Observable<Progress>(observer => {
    // Simulate upload progress
    let progress = 0;
    const interval = setInterval(() => {
      progress += 10;
      observer.next({ file, progress });
      if (progress >= 100) {
        clearInterval(interval);
        observer.complete();
      }
    }, 200);
  });
}

// Stream of files to upload
const filesToUpload: File[] = [/* ... list of File objects ... */];

// Create an Observable from the list of files
const uploadStream$ = from(filesToUpload);

