uploadStream$
  .pipe(
    mergeMap(file => uploadFile(file), 3) // <-- concurrency limit set to 3
  )
  .subscribe({
    next: (progress: Progress) => {
      console.log(`File: ${progress.file.name}, Progress: ${progress.progress}%`);
    },
