- Initializes the cart summary if the state is undefined
- Applies the event to update the cart summary
- Returns the updated state

---

### 📌 **Code Implementation**

```javascript
function project(state, event) {
  // If the state is undefined, initialize with the cart ID from the event
  if (!state) {
    return {
      id: event.cartId,
      itemCount: 0,
      totalCents: 0
    };
  }

  // Ensure the event is for the same cart as the state
  if (state.id !== event.cartId) {
    // This event belongs to a different cart; ignore it
    return state;
  }

  // Update the cart summary based on the event type
  switch (event.type) {
    case 'ItemAdded':
      return {
        ...state,
        itemCount: state.itemCount + event.quantity,
        totalCents: state.totalCents + event.quantity * event.unitPriceCents
      };

    case 'ItemRemoved':
      return {
        ...state,
        itemCount: state.itemCount - event.quantity,
        totalCents: state.totalCents - event.quantity * event.unitPriceCents
      };

    case 'QuantityUpdated':
      const delta = event.newQuantity - event.previousQuantity;
      return {
        ...state,
        itemCount: state.itemCount + delta,
        totalCents: state.totalCents + delta * event.unitPriceCents
      };

    default:
      // Ignore unknown event types
      return state;
  }
}
```

